ST.xhtml:
IF NOT GVL.x_Simulation_Mode THEN
    //MODALITÀ REALE
    //Mappatura diretta dai morsetti fisici del PLC alle variabili logiche interne.

    //Comandi operatore (Pulsanteria fisica)
    GVL.x_Start_Logic          := GVL.x_Start_Btn_HW;
    GVL.x_Stop_Logic           := GVL.x_Stop_Btn_HW;         // Cablato NC sul campo
    GVL.x_EStop_Logic          := GVL.x_EStop_Button_HW;     // Cablato NC sul campo
    GVL.x_Reset_Logic          := GVL.x_Reset_Btn_HW;

    //Sensori digitali di campo
    GVL.x_Filling_Sensor_Logic := GVL.x_Filling_Sensor_HW;
    GVL.x_Scale_Sensor_Logic   := GVL.x_Scale_Sensor_HW;
    GVL.x_Reject_Sensor_Logic  := GVL.x_Reject_Sensor_HW;
    GVL.x_Cylinder_Retracted_Logic := GVL.x_Cylinder_Retracted_HW;

ELSE
    //MODALITÀ SIMULAZIONE
    GVL.x_Start_Logic          := GVL.x_Start_Btn_HW;
    GVL.x_Stop_Logic           := GVL.x_Stop_Btn_HW;
    GVL.x_EStop_Logic          := GVL.x_EStop_Button_HW;
    GVL.x_Reset_Logic          := GVL.x_Reset_Btn_HW;
END_IF

//GENERATORE TRIGGERS E INTERBLOCCHI HMI
trig_Start(CLK := GVL.x_Start_Logic);
trig_Stop(CLK := GVL.x_Stop_Logic);

//gestione "Fermata Dolce" e reset grafico della pulsantiera
IF trig_Start.Q THEN
    GVL.x_Stop_Btn_HW := TRUE;        //rilascia graficamente il tasto di Stop (NC)
    GVL.x_Stop_Requested := FALSE;    //annulla un'eventuale richiesta di fermata a fine ciclo precedente
END_IF

IF trig_Stop.Q THEN
    GVL.x_Start_Btn_HW := FALSE;      //sgancia graficamente il tasto di Start per evitare stalli
END_IF

//GESTIONE DELLA SICUREZZA E ALLARMI MACCHINA
IF NOT GVL.x_EStop_Logic THEN
    //emergenza fisica
    GVL.e_CurrentState := E_MachineState.STATE_EMERGENCY;
    GVL.w_Active_Alarm_ID := 101;
    GVL.s_Active_Alarm_Msg := 'AL_101: EMERGENZA ATTIVA - Fungo premuto!';
    GVL.x_Reject_In_Progress := FALSE; 

ELSIF GVL.x_Alm_Too_Many_Rejects THEN
    //allarme qualità
    GVL.e_CurrentState := E_MachineState.STATE_EMERGENCY;
    GVL.w_Active_Alarm_ID := 102;

    //guida operatore dinamica: obbliga il passaggio in MANUALE per il riarmo
    IF NOT GVL.x_Key_Switch_Maint THEN
        IF GVL.x_Reset_Logic THEN
            GVL.s_Active_Alarm_Msg := 'AL_102: ERRORE! Passare in MANUALE prima di premere Reset!';
        ELSE
            GVL.s_Active_Alarm_Msg := 'AL_102: INTERBLOCCO - 3 scarti! Passare in MANUALE per riarmare.';
        END_IF
    ELSE
        GVL.s_Active_Alarm_Msg := 'AL_102: MANUALE inserito. Premere RESET per ripartire.';
    END_IF

ELSIF GVL.e_CurrentState = E_MachineState.STATE_EMERGENCY THEN
    //attesa riarmo 
    GVL.w_Active_Alarm_ID := 100;
    GVL.s_Active_Alarm_Msg := 'AL_100: SICUREZZE APERTE - In attesa di RESET.';
ELSE
    //condizione nominale
    GVL.w_Active_Alarm_ID := 0;
    GVL.s_Active_Alarm_Msg := 'Nessun Allarme - Linea in Sicurezza';
END_IF

//routine di riarmo
IF GVL.x_Reset_Logic AND GVL.x_EStop_Logic THEN

    //riarmo condizionato per allarme scarti 
    IF GVL.x_Alm_Too_Many_Rejects THEN
        IF GVL.x_Key_Switch_Maint THEN
            GVL.x_Alm_Too_Many_Rejects := FALSE;
            GVL.di_Consecutive_Rejects := 0;
        END_IF
    ELSE
        //reset standard di sicurezza 
        GVL.di_Consecutive_Rejects := 0; 
    END_IF

    GVL.x_Reject_In_Progress := FALSE;

    //riporta la macchina allo stato iniziale solo se non ci sono allarmi pendenti
    IF GVL.e_CurrentState = E_MachineState.STATE_EMERGENCY AND NOT GVL.x_Alm_Too_Many_Rejects THEN
        GVL.e_CurrentState := E_MachineState.STATE_INIT;
    END_IF

    GVL.x_Reset_Btn_HW := FALSE; //reset trigger per evitare riarmi ciclici
END_IF

//richiesta di Fermata Dolce (il ciclo in corso si concluderà ordinatamente)
IF NOT GVL.x_Stop_Logic THEN
    GVL.x_Stop_Requested := TRUE;
END_IF

//MACCHINA A STATI FINITA (FSM - Modalità Automatica)
IF NOT GVL.x_Key_Switch_Maint THEN 

    CASE GVL.e_CurrentState OF

        E_MachineState.STATE_INIT:
            GVL.s_PackML_State := 'STOPPED';
            GVL.x_Stop_Requested := FALSE;
            //interblocco di partenza: La macchina si arma solo a sicurezze ok e cilindro a riposo
            IF GVL.x_EStop_Logic AND GVL.x_Cylinder_Retracted_Logic AND NOT GVL.x_Alm_Too_Many_Rejects THEN
                GVL.e_CurrentState := E_MachineState.STATE_IDLE;
            END_IF

        E_MachineState.STATE_IDLE:
            GVL.s_PackML_State := 'IDLE';
            //reset variabili di tracking flacone
            GVL.di_Bottle_X_Pos := 0;
            GVL.di_Bottle_Y_Pos := 0;
            GVL.di_Bottle_Level := 0;
            GVL.x_Bottle_Falling := FALSE;
            GVL.x_Reject_In_Progress := FALSE;

            //transizione avviata dall'operatore
            IF GVL.x_Start_Logic AND NOT GVL.x_Stop_Requested THEN
                GVL.e_CurrentState := E_MachineState.STATE_CONVEYOR_RUN;
            END_IF

        E_MachineState.STATE_CONVEYOR_RUN:
            GVL.s_PackML_State := 'EXECUTE - RUNNING';
            IF GVL.x_Filling_Sensor_Logic AND NOT GVL.x_Bottle_Falling THEN
                GVL.e_CurrentState := E_MachineState.STATE_FILLING;
            END_IF

        E_MachineState.STATE_FILLING:
            GVL.s_PackML_State := 'EXECUTE - FILLING';
            IF fb_FillingTimer.Q THEN //attende la fine del dosaggio prima di avanzare
                GVL.e_CurrentState := E_MachineState.STATE_CHECK_WEIGHT;
            END_IF

        E_MachineState.STATE_CHECK_WEIGHT:
            GVL.s_PackML_State := 'EXECUTE - WEIGHING';
            //l'acquisizione del peso reale è demandata a PRG_Input. 
            //la FSM passa la responsabilità dello scarto alla stazione successiva.
            IF GVL.x_Scale_Sensor_Logic THEN
                GVL.e_CurrentState := E_MachineState.STATE_REJECT_VERIFY;
            END_IF

        E_MachineState.STATE_REJECT_VERIFY:
            GVL.s_PackML_State := 'EXECUTE - REJECT VERIFY';

            IF NOT GVL.x_Reject_In_Progress THEN
                IF GVL.x_Reject_Sensor_Logic THEN

                    IF GVL.x_Bottle_Is_Good THEN
                        //FLACONE CONFORME: aggiornamento immediato KPI e ripartenza
                        GVL.di_Total_Bottles := GVL.di_Total_Bottles + 1;
                        GVL.di_Good_Bottles := GVL.di_Good_Bottles + 1;
                        GVL.di_Consecutive_Rejects := 0; 

                        IF GVL.di_Total_Bottles > 0 THEN
                            GVL.r_Reject_Rate := (DINT_TO_REAL(GVL.di_Rejected_Bottles) / DINT_TO_REAL(GVL.di_Total_Bottles)) * 100.0;
                        END_IF

                        //valutazione richiesta di "Fermata Dolce"
                        IF GVL.x_Stop_Requested THEN
                            GVL.e_CurrentState := E_MachineState.STATE_IDLE;
                            GVL.x_Start_Btn_HW := FALSE; 
                        ELSE
                            GVL.e_CurrentState := E_MachineState.STATE_CONVEYOR_RUN;
                        END_IF
                    ELSE
                        //FLACONE NON CONFORME: innesca il ciclo pneumatico di scarto
                        GVL.x_Reject_In_Progress := TRUE;
                    END_IF

                END_IF
            ELSE
                //ATTESA COMPLETAMENTO SCARTO: il codice aspetta asincronamente la fine 
                //della corsa del cilindro prima di aggiornare i contatori ed eventualmente bloccarsi.
                IF fb_RejectTimer.Q THEN
                    GVL.x_Reject_In_Progress := FALSE; 

                    //aggiornamento KPI post-caduta fisica del pezzo
                    GVL.di_Total_Bottles := GVL.di_Total_Bottles + 1;
                    GVL.di_Rejected_Bottles := GVL.di_Rejected_Bottles + 1;
                    GVL.di_Consecutive_Rejects := GVL.di_Consecutive_Rejects + 1;

                    IF GVL.di_Total_Bottles > 0 THEN
                        GVL.r_Reject_Rate := (DINT_TO_REAL(GVL.di_Rejected_Bottles) / DINT_TO_REAL(GVL.di_Total_Bottles)) * 100.0;
                    END_IF

                    //valutazione ritardata dell'interblocco (Allarme Max Scarti)
                    IF GVL.di_Consecutive_Rejects >= 3 THEN
                        GVL.x_Alm_Too_Many_Rejects := TRUE;
                    ELSE
                        IF GVL.x_Stop_Requested THEN
                            GVL.e_CurrentState := E_MachineState.STATE_IDLE;
                            GVL.x_Start_Btn_HW := FALSE; 
                        ELSE
                            GVL.e_CurrentState := E_MachineState.STATE_CONVEYOR_RUN;
                        END_IF
                    END_IF
                END_IF
            END_IF

        E_MachineState.STATE_EMERGENCY:
            GVL.s_PackML_State := 'ABORTED';
            IF GVL.x_EStop_Logic AND GVL.x_Reset_Logic AND NOT GVL.x_Alm_Too_Many_Rejects THEN
                GVL.e_CurrentState := E_MachineState.STATE_INIT;
            END_IF

    END_CASE

ELSE
    //GESTIONE MANUALE (JOG)
    //sospende la FSM automatica forzandola in uno stato sicuro di attesa.
    GVL.s_PackML_State := 'MANUAL_MODE';

    IF GVL.e_CurrentState <> E_MachineState.STATE_EMERGENCY THEN
        GVL.e_CurrentState := E_MachineState.STATE_IDLE;
    END_IF

END_IF

//AGGIORNAMENTO TIMER E CONVERSIONE RICETTE
//converte il Setpoint (Secondi) inserito a pannello nel formato nativo TIME
GVL.t_FillingDuration := DINT_TO_TIME(GVL.di_Set_Time_Sec * 1000);

fb_FillingTimer(
    IN := (GVL.e_CurrentState = E_MachineState.STATE_FILLING), 
    PT := GVL.t_FillingDuration);

fb_RejectTimer(
    IN := GVL.x_Reject_In_Progress, 
    PT := GVL.t_RejectDuration);

//SCRITTURA BUFFER USCITE LOGICHE (Data Decoupling)
//la FSM non comanda direttamente i relè, ma compila un registro di intenzioni.
//garantisce che non ci siano uscite eccitate in conflitto in più punti del codice.
IF GVL.e_CurrentState <> E_MachineState.STATE_EMERGENCY THEN
    IF NOT GVL.x_Key_Switch_Maint THEN
        //LOGICA AUTO
        GVL.x_Cmd_Motor_Logic  := (GVL.e_CurrentState = E_MachineState.STATE_CONVEYOR_RUN) OR 
                                  (GVL.e_CurrentState = E_MachineState.STATE_CHECK_WEIGHT) OR
                                  (GVL.e_CurrentState = E_MachineState.STATE_REJECT_VERIFY AND NOT GVL.x_Reject_In_Progress);

        GVL.x_Cmd_Valve_Logic   := (GVL.e_CurrentState = E_MachineState.STATE_FILLING);
        GVL.x_Cmd_Cylinder_Logic := GVL.x_Reject_In_Progress;
    ELSE
        //LOGICA MANUALE (Con interblocchi di sicurezza)
        //es: nastro fermo se la valvola è aperta; dosatore inibito se manca il flacone.
        GVL.x_Cmd_Motor_Logic  := GVL.x_Man_Cmd_Conveyor AND NOT GVL.x_Cmd_Valve_Logic; 
        GVL.x_Cmd_Valve_Logic   := GVL.x_Man_Cmd_Valve AND GVL.x_Filling_Sensor_Logic;        
        GVL.x_Cmd_Cylinder_Logic := GVL.x_Man_Cmd_Cylinder;
    END_IF
ELSE
    //TAGLIO POTENZA IN EMERGENZA (Fail-Safe)
    GVL.x_Cmd_Motor_Logic  := FALSE;
    GVL.x_Cmd_Valve_Logic   := FALSE;
    GVL.x_Cmd_Cylinder_Logic := FALSE;
END_IF

//DISACCOPPIAMENTO ATTUATORI (Fail-Safe per Virtual Commissioning)
IF NOT GVL.x_Simulation_Mode THEN
    //MODALITÀ REALE
    //Trasferimento dei comandi calcolati in PRG_Core ai morsetti fisici (%QX)
    GVL.x_Cmd_Motor_HW    := GVL.x_Cmd_Motor_Logic;
    GVL.x_Cmd_Valve_HW    := GVL.x_Cmd_Valve_Logic;
    GVL.x_Cmd_Cylinder_HW := GVL.x_Cmd_Cylinder_Logic;
ELSE
    //MODALITÀ SIMULAZIONE
    //Sicurezza HIL (Hardware-In-the-Loop): Se il programma gira in simulazione 
    //su un PLC fisicamente cablato all'impianto, forza a zero i relè fisici.
    //Impedisce partenze accidentali della meccanica reale evitando danni.
    GVL.x_Cmd_Motor_HW    := FALSE;
    GVL.x_Cmd_Valve_HW    := FALSE;
    GVL.x_Cmd_Cylinder_HW := FALSE;
END_IF

//GESTIONE SEGNALAZIONI VISIVE (Torretta luminosa / HMI)
//Le segnalazioni ottiche non generano movimenti pericolosi, quindi 
//vengono aggiornate a prescindere dalla modalità (Reale/Simulazione).
IF GVL.e_CurrentState <> E_MachineState.STATE_EMERGENCY THEN
    GVL.x_Light_Ok_HW        := TRUE;     //luce Verde: Macchina sicura o in marcia
    GVL.x_Light_Alarm_HW     := FALSE;
ELSE
    GVL.x_Light_Ok_HW        := FALSE;
    GVL.x_Light_Alarm_HW     := TRUE;     //luce Rossa: Emergenza o blocco sicurezza
END_IF

//Avanzamento del clock di simulazione (sospeso in caso di emergenza)
IF GVL.e_CurrentState <> E_MachineState.STATE_EMERGENCY THEN
    di_Scan_Counter := di_Scan_Counter + 1; 
END_IF

//MOTORE GRAFICO E CINEMATICO (Eseguito solo in x_Simulation_Mode)
IF GVL.x_Simulation_Mode THEN

    //Reset posizione: simula il ricircolo continuo (loop) dei flaconi sulla linea
    IF GVL.di_Bottle_X_Pos > 700 THEN
        GVL.di_Bottle_X_Pos := 0;
        GVL.di_Bottle_Y_Pos := 0;
        GVL.di_Bottle_Level := 0;
    END_IF

    //Cinematica nastro: Avanzamento micrometrico in JOG (1px) o marcia automatica (4px)
    IF GVL.x_Cmd_Motor_Logic AND NOT GVL.x_Bottle_Falling THEN
        IF GVL.x_Key_Switch_Maint THEN
            GVL.di_Bottle_X_Pos := GVL.di_Bottle_X_Pos + 1; 
        ELSE
            GVL.di_Bottle_X_Pos := GVL.di_Bottle_X_Pos + 4; 
        END_IF
    END_IF

    //Simulazione dei sensori ottici a sbarramento
    //L'uso di ABS simula l'ingombro fisico del flacone (Beam Width).
    //L'interblocco (Y = 0) impedisce false letture mentre il flacone cade nel cesto scarti.
    GVL.x_Filling_Sensor_Logic := (ABS(GVL.di_Bottle_X_Pos - GVL.di_Pos_Sensor_Fill) <= GVL.di_Sensor_Beam_Width) AND (GVL.di_Bottle_Y_Pos = 0);
    GVL.x_Scale_Sensor_Logic   := (ABS(GVL.di_Bottle_X_Pos - GVL.di_Pos_Sensor_Scale) <= GVL.di_Sensor_Beam_Width) AND (GVL.di_Bottle_Y_Pos = 0);
    GVL.x_Reject_Sensor_Logic  := (ABS(GVL.di_Bottle_X_Pos - GVL.di_Pos_Sensor_Reject) <= GVL.di_Sensor_Beam_Width) AND (GVL.di_Bottle_Y_Pos = 0);

    //Simulazione fluidodinamica (Riempimento proporzionale)
    IF GVL.x_Cmd_Valve_Logic THEN
        IF NOT GVL.x_Key_Switch_Maint THEN
            //In AUTO: calcola il livello in base al tempo trascorso (ET / PT)
            IF GVL.t_FillingDuration > T#0S THEN
                GVL.di_Bottle_Level := TIME_TO_DINT(PRG_Core.fb_FillingTimer.ET) * 100 / TIME_TO_DINT(GVL.t_FillingDuration);
            END_IF
        ELSE
            //In MANUALE: incremento progressivo a comando operatore
            IF GVL.di_Bottle_Level < 100 THEN
                GVL.di_Bottle_Level := GVL.di_Bottle_Level + 1;
            END_IF
        END_IF
    END_IF

    //Simulazione cinematica attuatore pneumatico
    //Gli incrementi a step (+ o - 10) simulano il tempo fisico di estensione/ritrazione dello stelo
    IF GVL.x_Cmd_Cylinder_Logic THEN
        IF GVL.di_Cylinder_Stroke < 100 THEN
            GVL.di_Cylinder_Stroke := GVL.di_Cylinder_Stroke + 10;
        END_IF
    ELSE
        IF GVL.di_Cylinder_Stroke > 0 THEN
            GVL.di_Cylinder_Stroke := GVL.di_Cylinder_Stroke - 10;
        END_IF
    END_IF

    //Simulazione sensore magnetico di finecorsa (Cilindro a riposo)
    GVL.x_Cylinder_Retracted_Logic := (GVL.di_Cylinder_Stroke = 0);

    //Motore fisico: Valutazione collisione per lo scarto
    //Se lo stelo colpisce il flacone in corrispondenza del sensore, innesca la caduta
    IF (GVL.di_Cylinder_Stroke > 50) AND (ABS(GVL.di_Bottle_X_Pos - GVL.di_Pos_Sensor_Reject) <= 40) AND (GVL.di_Bottle_Y_Pos = 0) THEN
        GVL.x_Bottle_Falling := TRUE;
    END_IF

    //Gestione della gravità (Asse Y)
    IF GVL.x_Bottle_Falling THEN
        GVL.di_Bottle_Y_Pos := GVL.di_Bottle_Y_Pos + 5; 

        IF GVL.di_Bottle_Y_Pos > 100 THEN
            GVL.x_Bottle_Falling := FALSE;
            GVL.di_Bottle_X_Pos := 0;
            GVL.di_Bottle_Y_Pos := 0;
            GVL.di_Bottle_Level := 0;
        END_IF
    END_IF

    //CALCOLO PESO E FAULT INJECTION (DIGITAL TWIN BILANCIA)
    IF GVL.x_Scale_Sensor_Logic THEN
        //Calcolo peso teorico con aggiunta di rumore bianco (SIN) per simulare le vibrazioni industriali
        GVL.r_Measured_Weight := (DINT_TO_REAL(GVL.di_Bottle_Level) / 100.0 * GVL.r_Target_Weight) + (SIN(DINT_TO_REAL(di_Scan_Counter)) * 1.5);

        //INIEZIONE DETERMINISTICA DEI GUASTI
        //Sottodosa volutamente (-5g) i flaconi numero 7, 8 e 9 di ogni ciclo da 10
        //per innescare l'allarme 'AL_102' (3 scarti consecutivi) ai fini del testing
        IF (GVL.di_Total_Bottles MOD 10 = 7) OR 
           (GVL.di_Total_Bottles MOD 10 = 8) OR 
           (GVL.di_Total_Bottles MOD 10 = 9) THEN

            GVL.r_Measured_Weight := GVL.r_Measured_Weight - 5.0; 
        END_IF

    ELSIF GVL.di_Bottle_X_Pos < 200 THEN
        GVL.r_Measured_Weight := 0.0;
    END_IF

END_IF 

// GESTIONE SEGNALAZIONI E DIAGNOSTICA HMI
//Valutazione dei limiti di Specifica (USL/LSL)
GVL.x_Bottle_Is_Good := (GVL.r_Measured_Weight >= GVL.r_Tolerance_Min) AND (GVL.r_Measured_Weight <= GVL.r_Tolerance_Max);

//Generazione dinamica dei banner testuali per l'interfaccia operatore
IF GVL.r_Measured_Weight = 0.0 THEN
    GVL.s_Last_Reject_Reason := 'In attesa flacone...';
ELSE
    IF GVL.x_Key_Switch_Maint THEN
        IF GVL.x_Bottle_Is_Good THEN
            GVL.s_Last_Reject_Reason := 'OK: Conforme (Taratura)';
        ELSIF GVL.r_Measured_Weight < GVL.r_Tolerance_Min THEN
            GVL.s_Last_Reject_Reason := 'WRN_Q01: Sottodosaggio';
        ELSE
            GVL.s_Last_Reject_Reason := 'WRN_Q02: Sovradosaggio';
        END_IF
    ELSE
        IF GVL.e_CurrentState = E_MachineState.STATE_FILLING THEN
            GVL.s_Last_Reject_Reason := 'Dosaggio in corso...';
        ELSIF (GVL.e_CurrentState = E_MachineState.STATE_CHECK_WEIGHT) AND NOT GVL.x_Scale_Sensor_Logic THEN
            GVL.s_Last_Reject_Reason := 'In transito verso bilancia...';
        ELSIF GVL.x_Scale_Sensor_Logic THEN
            IF GVL.x_Bottle_Is_Good THEN
                GVL.s_Last_Reject_Reason := 'OK: Prodotto Conforme';
            ELSIF GVL.r_Measured_Weight < GVL.r_Tolerance_Min THEN
                GVL.s_Last_Reject_Reason := 'WRN_Q01: Sottodosaggio (Sotto LSL)';
            ELSE
                GVL.s_Last_Reject_Reason := 'WRN_Q02: Sovradosaggio (Sopra USL)';
            END_IF
        END_IF
    END_IF
END_IF

//HMI PULSE STRETCHING
//Congela l'uscita a TRUE per 500ms permettendo all'occhio umano di vedere 
//l'accensione dei LED anche con transiti del flacone molto rapidi
fb_Hmi_Scale_Led(IN := GVL.x_Scale_Sensor_Logic, PT := T#500MS);
GVL.x_Hmi_Scale_Vis := fb_Hmi_Scale_Led.Q;

fb_Hmi_Reject_Led(IN := GVL.x_Reject_Sensor_Logic, PT := T#500MS);
GVL.x_Hmi_Reject_Vis := fb_Hmi_Reject_Led.Q;
